from kafka import KafkaConsumer
import json

# Kafka consumer configuration
bootstrap_servers = ['localhost:9092']
consumer_group_id = 'financial_transactions_group'
topics = ['transactions']

# Create a Kafka consumer instance
consumer = KafkaConsumer(
    *topics,
    bootstrap_servers=bootstrap_servers,
    group_id=consumer_group_id,
    auto_offset_reset='earliest',
    enable_auto_commit=True,
    value_deserializer=lambda x: json.loads(x.decode('utf-8'))
)

# Define message handlers for different transaction types
def handle_deposit(transaction):
    # Business logic for deposit transactions
    print(f"Processing deposit: {transaction}")

def handle_withdrawal(transaction):
    # Business logic for withdrawal transactions
    print(f"Processing withdrawal: {transaction}")

def handle_transfer(transaction):
    # Business logic for transfer transactions
    print(f"Processing transfer: {transaction}")

# Dictionary to map transaction types to handlers
message_handlers = {
    'deposit': handle_deposit,
    'withdrawal': handle_withdrawal,
    'transfer': handle_transfer
}

# Consume messages and execute business logic
for message in consumer:
    transaction_type = message.value['type']
    transaction_data = message.value['data']

    if transaction_type in message_handlers:
        handler = message_handlers[transaction_type]
        handler(transaction_data)
    else:
        print(f"Unknown transaction type: {transaction_type}")